import screen from '@kyokuya/_shared/util/screen'
import type { ParticleEffectBubbleProps } from '@kyokuya/particle-bubble'
import { ParticleEffectBubble } from '@kyokuya/particle-bubble'
import { useParticleEffect2D } from '@kyokuya/particle-helper'
import cn from 'clsx'
import PropTypes from 'prop-types'
import React, { useContext, useMemo, useRef } from 'react'
import { PostLayoutActionsType } from '../context/actions'
import { PostLayoutContext } from '../context/context'
import AboutMePanel from './AboutMePanel'
import NavigationPanel from './NavigationPanel'
import SearchPanel from './SearchPanel'

const bubbleOptions: ParticleEffectBubbleProps = {}

export interface MagicPanelProps {
  /**
   * Navigation.
   */
  nav?: React.ReactNode
}

export const MagicPanel: React.FC<MagicPanelProps> = props => {
  const { nav } = props
  const { magicPanelVisible, magicPanelActivated, dispatch } =
    useContext(PostLayoutContext)
  const magicPanelRef = useRef<HTMLDivElement>(null)

  // Use particle effect when magic-panel is visible.
  useParticleEffect2D<ParticleEffectBubbleProps>(
    screen.lg ? null : magicPanelRef,
    ParticleEffectBubble,
    bubbleOptions,
    magicPanelVisible,
  )

  const { openNavigationPanel, openSearchPanel, openAboutMePanel } = useMemo<
    Record<
      'openNavigationPanel' | 'openSearchPanel' | 'openAboutMePanel',
      React.MouseEventHandler
    >
  >(
    () => ({
      openNavigationPanel: e => {
        e.stopPropagation()
        dispatch({
          type: PostLayoutActionsType.ACTIVE_MAGIC_PANEL,
          payload: { panel: 'navigation' },
        })
      },
      openSearchPanel: e => {
        e.stopPropagation()
        dispatch({
          type: PostLayoutActionsType.ACTIVE_MAGIC_PANEL,
          payload: { panel: 'search' },
        })
      },
      openAboutMePanel: e => {
        e.stopPropagation()
        dispatch({
          type: PostLayoutActionsType.ACTIVE_MAGIC_PANEL,
          payload: { panel: 'about-me' },
        })
      },
    }),
    [dispatch],
  )

  return (
    <div
      ref={magicPanelRef}
      className={cn(
        'kyokuya-post-magic-panel',
        { 'kyokuya-post-magic-panel--visible': magicPanelVisible },
        'kyokuya-post__frosted-glass-panel',
      )}
      onClick={e => void e.stopPropagation()}
    >
      <div className="kyokuya-post-magic-panel__header">
        <div className="kyokuya-post-magic-panel__nav">
          <span
            key="navigation"
            className={cn('kyokuya-post-magic-panel__nav-item', {
              'kyokuya-post-magic-panel__nav-item--active':
                magicPanelActivated === 'navigation',
            })}
            onClick={openNavigationPanel}
          >
            目录
          </span>
          <span
            key="delimiter-1"
            className="kyokuya-post-magic-panel__nav-delimiter"
          />
          <span
            key="search"
            className={cn('kyokuya-post-magic-panel__nav-item', {
              'kyokuya-post-magic-panel__nav-item--active':
                magicPanelActivated === 'search',
            })}
            onClick={openSearchPanel}
          >
            检索
          </span>
          <span
            key="delimiter-2"
            className="kyokuya-post-magic-panel__nav-delimiter"
          />
          <span
            key="about-me"
            className={cn('kyokuya-post-magic-panel__nav-item', {
              'kyokuya-post-magic-panel__nav-item--active':
                magicPanelActivated === 'about-me',
            })}
            onClick={openAboutMePanel}
          >
            关于我
          </span>
        </div>
      </div>
      <div className="kyokuya-post-magic-panel__main">
        <NavigationPanel hidden={magicPanelActivated !== 'navigation'}>
          {nav}
        </NavigationPanel>
        <SearchPanel hidden={magicPanelActivated !== 'search'} />
        <AboutMePanel hidden={magicPanelActivated !== 'about-me'} />
      </div>
    </div>
  )
}

MagicPanel.propTypes = {
  nav: PropTypes.node,
}

MagicPanel.displayName = 'KyokuyaLayoutPostMagicPanel'
export default MagicPanel
