import LinkRenderer from '@kyokuya/react-link'
import { LinkReferenceType, LinkType, TextType } from '@yozora/ast'
import type { TokenRendererMap } from '@yozora/react-markdown'
import { YozoraMarkdownContext } from '@yozora/react-markdown'
import React from 'react'

export const defaultCustomRendererMap: Partial<TokenRendererMap> = {
  [LinkType]: function KyokuyaYozoraLink(link) {
    const { url, title } = link
    return (
      <YozoraMarkdownContext.Consumer>
        {({ renderYozoraNodes }) => (
          <LinkRenderer url={url} title={title}>
            {renderYozoraNodes(link.children)}
          </LinkRenderer>
        )}
      </YozoraMarkdownContext.Consumer>
    )
  },
  [LinkReferenceType]: function KyokuyaYozoraLinkReference(linkReference) {
    return (
      <YozoraMarkdownContext.Consumer>
        {({ getDefinition, renderYozoraNodes }) => {
          const definition = getDefinition(linkReference.identifier)
          const url: string = definition?.url ?? ''
          const title: string | undefined = definition?.title
          return (
            <LinkRenderer url={url} title={title}>
              {renderYozoraNodes(linkReference.children)}
            </LinkRenderer>
          )
        }}
      </YozoraMarkdownContext.Consumer>
    )
  },
  [TextType]: function KyokuyaYozoraText(text) {
    return <React.Fragment>{text.value}</React.Fragment>
  },
}

export default defaultCustomRendererMap
